import itertools
class Solution:
    def findMaximumElegance(self, items, k):
        n = len(items)
        best = None
        for combo in itertools.combinations(range(n), k):
            total = 0
            cats = set()
            for idx in combo:
                total += items[idx][0]
                cats.add(items[idx][1])
            val = total + len(cats) ** 2
            if best is None or val > best:
                best = val
        return best

