var findMaximumElegance = function(items, k) {
    const sorted = [...items].sort((a, b) => b[0] - a[0]);
    const n = sorted.length;
    const seen = new Set();
    const stack = [];
    let total = 0;
    for (let i = 0; i < k; i++) {
        const [profit, cat] = sorted[i];
        total += profit;
        if (seen.has(cat)) {
            stack.push(profit);
        } else {
            seen.add(cat);
        }
    }
    let distinct = seen.size;
    let ans = total + distinct * distinct;
    for (let i = k; i < n; i++) {
        const [profit, cat] = sorted[i];
        if (!seen.has(cat) && stack.length > 0) {
            const d = stack.pop();
            total += profit - d;
            seen.add(cat);
            distinct += 1;
            ans = Math.max(ans, total + distinct * distinct);
        }
    }
    return ans;
};
